object Solution {
  /**
    * @param nums The circular integer array.
    * @param k The target number of peaks.
    * @return The minimum number of operations, or -1 if impossible.
    */
  def solve(nums: Array[Long], k: Long): Long = {
    val n = nums.length
    val kLong = k
    val kInt = k.toInt

    // 1. Check maximum possible peaks
    // Maximum number of peaks is floor(N/2)
    if (kInt > n / 2) {
      return -1L
    }

    // 2. Calculate initial number of peaks
    var initialCount = 0
    for (i <- 0 until n) {
      val prev = nums[(i - 1 + n) % n]
      val current = nums(i)
      val next = nums[(i + 1) % n]
      if (current > prev && current > next) {
        initialCount += 1
      }
    }

    if (initialCount >= kInt) {
      return 0L
    }

    // 3. Greedy approach simulation (based on local minimum cost to become a peak)
    // This approach is a heuristic due to coupling effects, but it's the most feasible path without a full DP/Flow solution.

    // Structure to hold cost and index
    case class Candidate(cost: Long, index: Int)

    val candidates = new Array[Candidate](n)
    for (i <- 0 until n) {
      val prev = nums[(i - 1 + n) % n]
      val next = nums[(i + 1) % n]
      // Minimum cost to make nums[i] strictly greater than its neighbors (assuming neighbors don't change)
      val requiredIncrease = Math.max(0, Math.max(prev, next) + 1 - nums(i))
      candidates(i) = Candidate(requiredIncrease, i)
    }

    // Sort candidates by required initial cost
    val sortedCandidates = candidates.sortBy(_.cost)

    var totalCost: Long = 0
    var currentNums = nums.clone()
    val selectedIndices = new java.util.HashSet[Int]()

    // Iteratively select candidates until K distinct peaks are achieved or we run out of candidates
    for (candidate in sortedCandidates) {
      if (selectedIndices.size >= kInt) break

      val i = candidate.index
      if (selectedIndices.contains(i)) continue

      // Recalculate required increase based on the *current* state of the array simulation
      val prev = currentNums[(i - 1 + n) % n]
      val next = currentNums[(i + 1) % n]

      val requiredIncrease = Math.max(0, Math.max(prev, next) + 1 - currentNums(i))

      if (requiredIncrease > 0) {
        // Apply the increase
        totalCost += requiredIncrease
        currentNums(i) += requiredIncrease
        selectedIndices.add(i)
      } else {
        // If requiredIncrease is 0, it means it's already a peak or equal to neighbors. 
        // If it's already a peak, it would have been counted in initialCount, unless neighbors were increased by other selections.
        // Since we are iterating based on *initial* cost, if cost is 0, we must check if it *is* a peak in the current state, or if it's just equal.
        // To maintain the greedy choice structure, we only add it if it contributes to reaching K. If cost is 0, we add it if it is currently a peak.

        val currentPrev = currentNums[(i - 1 + n) % n]
        val currentNext = currentNums[(i + 1) % n]
        if (currentNums(i) > currentPrev && currentNums(i) > currentNext) {
             // It's already a peak in the current simulation state (cost 0)
             selectedIndices.add(i)
        }
      }
    }

    if (selectedIndices.size < kInt) {
      return -1L
    }

    totalCost
  }
}
