   */
  def solve(nums: Array[Long], k: Long): Long = {
    val n = nums.length
    val kInt = k.toInt

    // 1. Check maximum possible peaks
    if (k > (n / 2).toInt) {
      return -1
    }

    // 2. Calculate potential cost for each element to become a peak assuming neighbors are unchanged.
    case class PotentialPeak(cost: Long, index: Int)

