    * @param k The target minimum number of peaks.
    * @return The minimum number of operations, or -1 if impossible.
    */
  def solve(nums: Array[Long], k: Long): Long = {
    val n = nums.length
    val targetK = k.toInt

    // 1. Check maximum possible peaks
    // Max peaks in a circular array of size N is floor(N/2).
    if (targetK > n / 2) {
      return -1
    }

    // 2. Calculate initial number of peaks
    var initialCount = 0
    for (i <- 0 until n) {
      val prev = nums[(i - 1 + n) % n]
      val current = nums(i)
      val next = nums[(i + 1) % n]
      if (current > prev && current > next) {
        initialCount += 1
      }
    }

    if (initialCount >= targetK) {
      return 0
    }

    // 3. Greedy approach: Select K candidates that require the minimum *initial* increase,
    // and simulate the process iteratively, as increases affect subsequent costs.

    // We need to find the minimum total increase. This problem is hard due to coupling.
    // We use a simulation approach: repeatedly find the cheapest way to create *one more* peak
    // until we reach K peaks, updating the array in each step.

    var currentNums = nums.clone()
    var currentPeaks = initialCount
    var totalCost: Long = 0

    while (currentPeaks < targetK) {
      var minCostForNextPeak: Long = Long.MaxValue
      var bestIndex: Int = -1

      // Iterate over all potential indices to see which one requires the least cost increase to become a peak *now*.
      for (i <- 0 until n) {
        val prev = currentNums[(i - 1 + n) % n]
        val next = currentNums[(i + 1) % n]

        // Check if i is already a peak (if so, we don't need to increase it unless we are forced to,
